        CP $07                           ; $DE24  FE 07
        JR NZ,SUB_DD8E_6                 ; $DE26  20 05
        LD A,$02                         ; $DE28  3E 02
        LD (L_DEA3),A                    ; $DE2A  32 A3 DE
